import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X, Instagram, Facebook } from "lucide-react";
import Logo from "/Users/deepak/Desktop/dod2/src/assets/images/logo.png";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const menuItems = [
    { title: "Home", path: "/" },
    { title: "Academy", path: "/academy" },
    { title: "Pro Services", path: "/pro-services" },
    { title: "Our Story", path: "/story" },
    { title: "Connect", path: "/connect" },
  ];

  return (
    <nav
      className={`fixed w-full z-50 transition-all duration-500 ${
        scrolled
          ? "bg-charcoal/95 backdrop-blur-xl border-b border-gold/30 shadow-elegant"
          : "bg-charcoal/60 backdrop-blur-md border-b border-gold/10"
      }`}
    >
      <div className="max-w-7xl mx-auto px-6 lg:px-12">
        <div className="flex justify-between items-center h-20">
          {/* Logo */}
          <Link
            to="/"
            className="flex items-center group transition-transform duration-300 hover:scale-105"
          >
            <img
              src={Logo}
              alt="DOD Logo"
              className="h-12 w-auto drop-shadow-lg"
            />
          </Link>

          {/* Desktop Menu */}
          <div className="hidden md:flex space-x-10">
            {menuItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className="relative text-sm font-montserrat uppercase tracking-widest text-ivory/80 hover:text-gold transition-all duration-300 group"
              >
                {item.title}
                <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-gradient-to-r from-gold to-transparent group-hover:w-full transition-all duration-300" />
              </Link>
            ))}
          </div>

          {/* Social Icons + Mobile Toggle */}
          <div className="flex items-center space-x-6">
            <div className="hidden sm:flex items-center space-x-4">
              <a
                href="#"
                className="text-ivory/60 hover:text-gold transition-colors duration-300 hover:scale-110 transform"
                aria-label="Instagram"
              >
                <Instagram className="w-5 h-5" />
              </a>
              <a
                href="#"
                className="text-ivory/60 hover:text-gold transition-colors duration-300 hover:scale-110 transform"
                aria-label="Facebook"
              >
                <Facebook className="w-5 h-5" />
              </a>
            </div>

            {/* Mobile Toggle */}
            <button
              className="md:hidden text-gold hover:text-ivory transition-colors duration-300 p-2"
              onClick={() => setIsOpen(!isOpen)}
              aria-label="Toggle menu"
            >
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Drawer */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, x: "100%" }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: "100%" }}
            transition={{ type: "spring", damping: 25, stiffness: 200 }}
            className="fixed inset-0 top-20 bg-charcoal/98 backdrop-blur-xl z-40 flex flex-col items-center justify-center space-y-8 border-t border-gold/20"
          >
            {menuItems.map((item, index) => (
              <motion.div
                key={item.path}
                initial={{ opacity: 0, x: 50 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: index * 0.1 }}
              >
                <Link
                  to={item.path}
                  onClick={() => setIsOpen(false)}
                  className="text-2xl font-cinzel tracking-widest text-ivory hover:text-gold transition-colors duration-300"
                >
                  {item.title}
                </Link>
              </motion.div>
            ))}

            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.5 }}
              className="flex space-x-6 pt-8 border-t border-gold/20 mt-8"
            >
              <Instagram className="w-6 h-6 text-gold/60 hover:text-gold cursor-pointer transition-colors" />
              <Facebook className="w-6 h-6 text-gold/60 hover:text-gold cursor-pointer transition-colors" />
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;
